describe("drain sink abort", () => {
  it("should abort stream and call done with null when no error", (done) => {
    let calls = 0;
    let pendingCb: ((end: any, data?: any) => void) | null = null;

    const source = (end: any, cb: (end: any, data?: any) => void) => {
      if (end) {
        cb(end);
        return;
      }
      pendingCb = cb;
    };

    const sink = drain(
      (data: any) => {},
      (err: any) => {
        expect(err).toBeNull();
        done();
      }
