    sink(source);

    // Trigger the source to provide data, keeping the loop going
    if (pendingCb) {
      const cb = pendingCb;
      pendingCb = null;
      cb(null, 1);
    }

    // Now abort - pendingCb should be set again
    if (pendingCb) {
      sink.abort();
      const cb = pendingCb;
      pendingCb = null;
      cb(true);
    }
  });
